"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import {
  Heart,
  Search,
  MapPin,
  Building2,
  Filter,
  Star,
  Activity,
  Bed,
  CheckCircle2,
  Phone,
  ArrowRight,
  Shield,
  Loader2,
  ArrowLeft,
} from "lucide-react";
import Link from "next/link";

interface Hospital {
  id: string;
  name: string;
  phone: string;
  email: string;
  description: string;
  address: string;
  city: string;
  state: string;
  pincode: string;
  isOpen24Hours: boolean;
  acceptedInsurances: string[];
  avgRating: number;
  totalRatings: number;
  specializations: { name: string }[];
  beds: { type: string; total: number; available: number; pricePerDay: number }[];
  doctors: { id: string; name: string; specialization: string }[];
}

export default function HospitalsDiscoveryPage() {
  const router = useRouter();
  const [hospitals, setHospitals] = useState<Hospital[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [selectedCity, setSelectedCity] = useState("");
  const [selectedSpecialty, setSelectedSpecialty] = useState("");
  const [selectedInsurance, setSelectedInsurance] = useState("");

  const [cities, setCities] = useState<string[]>([]);
  const [specialties, setSpecialties] = useState<string[]>([]);
  const [insurances, setInsurances] = useState<string[]>([]);

  // Fetch initial list of hospitals and populate filter options
  useEffect(() => {
    async function fetchData() {
      try {
        setLoading(true);
        const queryParams = new URLSearchParams();
        if (search) queryParams.set("search", search);
        if (selectedCity) queryParams.set("city", selectedCity);
        if (selectedSpecialty) queryParams.set("specialty", selectedSpecialty);
        if (selectedInsurance) queryParams.set("insurance", selectedInsurance);

        const res = await fetch(`/api/hospitals?${queryParams.toString()}`);
        const data = await res.json();
        
        if (data.success) {
          setHospitals(data.data);
          
          // Dynamically populate filters based on all returned results if they aren't filtered yet
          if (!search && !selectedCity && !selectedSpecialty && !selectedInsurance) {
            const allCities = new Set<string>();
            const allSpecs = new Set<string>();
            const allInsurances = new Set<string>();

            data.data.forEach((h: Hospital) => {
              if (h.city) allCities.add(h.city);
              h.specializations.forEach(s => allSpecs.add(s.name));
              h.acceptedInsurances.forEach(i => allInsurances.add(i));
            });

            setCities(Array.from(allCities));
            setSpecialties(Array.from(allSpecs));
            setInsurances(Array.from(allInsurances));
          }
        }
      } catch (err) {
        console.error("Error fetching hospitals:", err);
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, [search, selectedCity, selectedSpecialty, selectedInsurance]);

  const clearFilters = () => {
    setSearch("");
    setSelectedCity("");
    setSelectedSpecialty("");
    setSelectedInsurance("");
  };

  return (
    <div className="min-h-screen bg-surface-secondary">
      {/* Header */}
      <header className="bg-white border-b border-border sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button
              onClick={() => router.push("/dashboard")}
              className="text-text-muted hover:text-text-primary p-2 -ml-2 rounded-lg hover:bg-surface-secondary transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <div className="w-8 h-8 gradient-bg rounded-lg flex items-center justify-center">
              <Heart className="w-4.5 h-4.5 text-white" />
            </div>
            <span className="text-lg font-bold gradient-text">HealthBridge</span>
          </div>
          <div className="text-sm font-medium text-text-secondary">Hospital Discovery</div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-text-primary mb-2">Find the Right Hospital</h1>
          <p className="text-text-secondary">
            Search and compare facilities, view bed availability, check accepted insurances, and book consultations.
          </p>
        </div>

        <div className="grid lg:grid-cols-4 gap-8">
          {/* Filters - Left Column */}
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-2xl border border-border p-5 space-y-5">
              <div className="flex items-center justify-between">
                <span className="font-semibold text-text-primary flex items-center gap-2">
                  <Filter className="w-4 h-4 text-primary-600" /> Filters
                </span>
                {(search || selectedCity || selectedSpecialty || selectedInsurance) && (
                  <button
                    onClick={clearFilters}
                    className="text-xs font-semibold text-primary-600 hover:text-primary-800 transition-colors"
                  >
                    Clear All
                  </button>
                )}
              </div>

              {/* City Filter */}
              <div className="space-y-2">
                <label className="text-xs font-bold text-text-muted uppercase tracking-wider">City</label>
                <select
                  value={selectedCity}
                  onChange={(e) => setSelectedCity(e.target.value)}
                  className="w-full text-sm border border-border rounded-xl px-3 py-2.5 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                >
                  <option value="">All Cities</option>
                  {cities.map((city) => (
                    <option key={city} value={city}>
                      {city}
                    </option>
                  ))}
                </select>
              </div>

              {/* Specialty Filter */}
              <div className="space-y-2">
                <label className="text-xs font-bold text-text-muted uppercase tracking-wider">Specialty</label>
                <select
                  value={selectedSpecialty}
                  onChange={(e) => setSelectedSpecialty(e.target.value)}
                  className="w-full text-sm border border-border rounded-xl px-3 py-2.5 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                >
                  <option value="">All Specialties</option>
                  {specialties.map((spec) => (
                    <option key={spec} value={spec}>
                      {spec}
                    </option>
                  ))}
                </select>
              </div>

              {/* Insurance Filter */}
              <div className="space-y-2">
                <label className="text-xs font-bold text-text-muted uppercase tracking-wider">Insurance Accepted</label>
                <select
                  value={selectedInsurance}
                  onChange={(e) => setSelectedInsurance(e.target.value)}
                  className="w-full text-sm border border-border rounded-xl px-3 py-2.5 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                >
                  <option value="">All Insurances</option>
                  {insurances.map((ins) => (
                    <option key={ins} value={ins}>
                      {ins}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          </div>

          {/* Results - Right 3 Columns */}
          <div className="lg:col-span-3 space-y-6">
            {/* Search Input */}
            <div className="relative">
              <Search className="absolute left-4 top-3.5 h-5 w-5 text-text-muted" />
              <input
                type="text"
                placeholder="Search hospitals by name, specializations..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full pl-11 pr-4 py-3 border border-border rounded-2xl bg-white text-text-primary focus:outline-none focus:border-primary-400 focus:ring-1 focus:ring-primary-400 transition-all shadow-xs placeholder-text-muted text-sm sm:text-base"
              />
            </div>

            {loading ? (
              <div className="flex flex-col items-center justify-center py-20 bg-white border border-border rounded-2xl gap-3">
                <Loader2 className="w-8 h-8 text-primary-600 animate-spin" />
                <p className="text-sm text-text-secondary">Searching matching hospitals...</p>
              </div>
            ) : hospitals.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 bg-white border border-border rounded-2xl text-center px-4">
                <Building2 className="w-12 h-12 text-text-muted mb-4" />
                <h3 className="text-lg font-bold text-text-primary mb-1">No Hospitals Found</h3>
                <p className="text-sm text-text-secondary max-w-md">
                  We couldn't find any hospitals matching your filter choices. Try clearing some filters or searching for another term.
                </p>
                <button
                  onClick={clearFilters}
                  className="mt-5 inline-flex items-center justify-center px-4 py-2 border border-primary-600 text-sm font-semibold text-primary-600 bg-white rounded-xl hover:bg-primary-50 transition-colors"
                >
                  Clear Filters
                </button>
              </div>
            ) : (
              <div className="grid md:grid-cols-2 gap-6">
                {hospitals.map((hospital) => {
                  const totalBedsAvailable = hospital.beds?.reduce((sum, b) => sum + b.available, 0) || 0;
                  
                  return (
                    <div
                      key={hospital.id}
                      className="bg-white border border-border rounded-2xl p-6 hover-lift flex flex-col justify-between"
                    >
                      <div>
                        {/* Title & Rating */}
                        <div className="flex justify-between items-start mb-2">
                          <h2 className="text-lg font-bold text-text-primary hover:text-primary-700 transition-colors">
                            <Link href={`/hospitals/${hospital.id}`}>{hospital.name}</Link>
                          </h2>
                          <div className="flex items-center gap-1 bg-amber-50 text-amber-700 px-2 py-0.5 rounded-lg text-xs font-semibold">
                            <Star className="w-3.5 h-3.5 fill-amber-500 text-amber-500" />
                            <span>{hospital.avgRating.toFixed(1)}</span>
                          </div>
                        </div>

                        {/* Location */}
                        <p className="text-sm text-text-secondary flex items-center gap-1.5 mb-4">
                          <MapPin className="w-4 h-4 text-text-muted flex-shrink-0" />
                          <span>{hospital.address}, {hospital.city}</span>
                        </p>

                        {/* Specialization Tags */}
                        <div className="flex flex-wrap gap-1.5 mb-4">
                          {hospital.specializations.slice(0, 3).map((spec) => (
                            <span
                              key={spec.name}
                              className="text-xs px-2.5 py-1 bg-surface-secondary text-text-secondary rounded-lg font-medium"
                            >
                              {spec.name}
                            </span>
                          ))}
                          {hospital.specializations.length > 3 && (
                            <span className="text-xs px-2 py-1 bg-surface-secondary text-text-muted rounded-lg font-medium">
                              +{hospital.specializations.length - 3} more
                            </span>
                          )}
                        </div>

                        {/* Bed counts & quick summary */}
                        <div className="grid grid-cols-2 gap-3 bg-surface-secondary rounded-xl p-3.5 mb-4 text-xs">
                          <div>
                            <span className="text-text-muted block mb-0.5">Avail. Beds</span>
                            <span className="font-bold text-text-primary flex items-center gap-1">
                              <Bed className="w-3.5 h-3.5 text-primary-500" />
                              {totalBedsAvailable > 0 ? (
                                <span className="text-emerald-600 font-semibold">{totalBedsAvailable} Beds</span>
                              ) : (
                                <span className="text-error font-semibold">None Available</span>
                              )}
                            </span>
                          </div>
                          <div>
                            <span className="text-text-muted block mb-0.5">Services</span>
                            <span className="font-bold text-text-primary flex items-center gap-1">
                              <Activity className="w-3.5 h-3.5 text-accent-500" />
                              {hospital.isOpen24Hours ? "Open 24/7" : "Day Clinic"}
                            </span>
                          </div>
                        </div>

                        {/* Insurance accepted block */}
                        {hospital.acceptedInsurances.length > 0 && (
                          <div className="flex items-center gap-1.5 mb-6 text-xs text-text-secondary">
                            <Shield className="w-3.5 h-3.5 text-emerald-500 flex-shrink-0" />
                            <span className="font-medium truncate">
                              Accepts {hospital.acceptedInsurances.slice(0, 2).join(", ")}
                              {hospital.acceptedInsurances.length > 2 && " & more"}
                            </span>
                          </div>
                        )}
                      </div>

                      <div className="pt-4 border-t border-border flex items-center justify-between">
                        <span className="text-xs text-text-muted flex items-center gap-1">
                          <Phone className="w-3.5 h-3.5" /> {hospital.phone}
                        </span>
                        <Link
                          href={`/hospitals/${hospital.id}`}
                          className="inline-flex items-center gap-1 text-sm font-semibold text-primary-600 hover:text-primary-800 transition-all group"
                        >
                          View Profile
                          <ArrowRight className="w-4 h-4 group-hover:translate-x-0.5 transition-transform" />
                        </Link>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
}
